// === Java program Execution steps ===

// Step1: Create a source file
//   Hello.java Save with filename

// Step2: Compile (convert source code)
//   javac Hello.java
//   → Hello.class(bytecode) is generated

// Step3: Execute (run the program)
//   java Hello
//   → Message on screen is displayed

// Java program basic structure
// All code is written inside a class
public class Hello {
    // mainMethod: Program entry point
    public static void main(String[] args) {
        // Message to console to display
        System.out.println("Hello, World!");
    }
}

